// src/components/ERPChatBot/ERPChatBot.jsx
import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';
import { 
  Send, X, Bot, User, Loader2, 
  Sparkles, ChevronRight, Clock,
  BookOpen, DollarSign, Calendar,
  TrendingUp, FileText, MessageCircle,
  AlertCircle
} from 'lucide-react';
import './ERPChatBot.css';

const ERPChatBot = ({ studentId, studentName, onClose }) => {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [suggestions, setSuggestions] = useState([]);
  const [isTyping, setIsTyping] = useState(false);
  const [connectionStatus, setConnectionStatus] = useState('checking');
  const messagesEndRef = useRef(null);

  // Check connection on mount
  useEffect(() => {
    checkConnection();
    loadSuggestions();
  }, []);

  // Initial messages
  useEffect(() => {
    const welcomeMessages = [{
      id: 1,
      text: `Hi ${studentName || 'Student'}! 👋 I'm your AI Assistant. I can help you with:\n\n📚 **Courses & Teachers**\n💰 **Fees & Payments**\n📅 **Attendance & Schedule**\n🎯 **Grades & GPA**\n📝 **Assignments & Tasks**\n📊 **Academic Progress**\n\nWhat would you like to know?`,
      sender: 'bot',
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
      icon: '🤖',
      type: 'welcome'
    }];

    setMessages(welcomeMessages);
  }, [studentName]);

  // Check chatbot service connection
  const checkConnection = async () => {
    try {
      const response = await axios.get('http://localhost:50000/api/chatbot/health', {
        withCredentials: true
      });
      
      if (response.data.success) {
        setConnectionStatus('connected');
        console.log('✅ Chatbot service connected:', response.data);
      } else {
        setConnectionStatus('error');
      }
    } catch (error) {
      console.error('❌ Chatbot service connection failed:', error);
      setConnectionStatus('error');
      
      // Add error message
      const errorMessage = {
        id: Date.now(),
        text: "⚠️ Chatbot service is temporarily unavailable. Please try again later.",
        sender: 'bot',
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        icon: '⚠️',
        type: 'error'
      };
      setMessages(prev => [...prev, errorMessage]);
    }
  };

  const loadSuggestions = () => {
    const defaultSuggestions = [
      { text: "What courses am I taking this semester?", icon: "📚", category: "courses" },
      { text: "How much fee do I need to pay?", icon: "💰", category: "fees" },
      { text: "What's my attendance percentage?", icon: "📊", category: "attendance" },
      { text: "Show me my grades and GPA", icon: "📈", category: "grades" },
      { text: "Who are my teachers this semester?", icon: "👨‍🏫", category: "teachers" },
      { text: "What assignments do I have?", icon: "📝", category: "assignments" },
      { text: "What's my timetable for today?", icon: "🕒", category: "timetable" },
      { text: "How many credits have I completed?", icon: "🎯", category: "progress" }
    ];
    setSuggestions(defaultSuggestions);
  };

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMessage = {
      id: Date.now(),
      text: input,
      sender: 'user',
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
      icon: '👤',
      type: 'question'
    };
    
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);
    setIsTyping(true);

    try {
      console.log('📤 Sending question:', input);
      
      // IMPORTANT: Don't send studentId in body - it comes from session
      const response = await axios.post('http://localhost:50000/api/chatbot/ask', 
        {
          question: input
          // DO NOT include studentId here - it comes from session
        }, 
        {
          withCredentials: true,
          headers: {
            'Content-Type': 'application/json'
          }
        }
      );

      console.log('✅ Response received:', response.data);

      setIsTyping(false);

      const botMessage = {
        id: Date.now() + 1,
        text: response.data.answer,
        sender: 'bot',
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        icon: '🤖',
        type: 'answer',
        data: response.data
      };
      
      setMessages(prev => [...prev, botMessage]);

    } catch (error) {
      setIsTyping(false);
      console.error("❌ Chatbot error:", error);
      
      let errorText = "Sorry, I'm having trouble processing your question. Please try again.";
      
      if (error.response) {
        // Server responded with error
        switch (error.response.status) {
          case 401:
            errorText = "Please log in to use the AI assistant.";
            break;
          case 403:
            errorText = "Only students can access this feature.";
            break;
          case 500:
            errorText = "Server error. Please try again later.";
            break;
        }
      } else if (error.request) {
        // Request made but no response
        errorText = "Cannot connect to the chatbot service. Please check your internet connection.";
      }
      
      const errorMessage = {
        id: Date.now() + 1,
        text: errorText,
        sender: 'bot',
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        icon: '⚠️',
        isError: true
      };
      
      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleQuickQuestion = (question) => {
    setInput(question);
    // Auto-send after setting the input
    setTimeout(() => {
      const sendBtn = document.querySelector('.send-btn');
      if (sendBtn && !sendBtn.disabled) {
        handleSend();
      }
    }, 100);
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const clearChatHistory = async () => {
    try {
      await axios.post('http://localhost:50000/api/chatbot/clear-history', {}, {
        withCredentials: true
      });
      
      // Reset messages to just welcome
      const welcomeMessages = [{
        id: Date.now(),
        text: `Chat history cleared! How can I help you today?`,
        sender: 'bot',
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        icon: '🤖',
        type: 'system'
      }];
      
      setMessages(welcomeMessages);
      
    } catch (error) {
      console.error('Error clearing history:', error);
    }
  };

  const getConnectionStatusIcon = () => {
    switch (connectionStatus) {
      case 'connected': return <div className="status-indicator connected"></div>;
      case 'error': return <AlertCircle size={12} color="#ff6b6b" />;
      default: return <div className="status-indicator checking"></div>;
    }
  };

  return (
    <div className="erp-chatbot">
      {/* Header */}
      <div className="chatbot-header">
        <div className="header-left">
          <div className="ai-badge">
            <Bot size={18} />
            <span>ERP AI Assistant</span>
            <div className="connection-status">
              {getConnectionStatusIcon()}
              <span className="status-text">
                {connectionStatus === 'connected' ? 'Online' : 
                 connectionStatus === 'error' ? 'Offline' : 'Connecting...'}
              </span>
            </div>
          </div>
          <div className="student-info">
            <span className="student-name">{studentName || 'Student'}</span>
            {studentId && <span className="student-id">• {studentId}</span>}
          </div>
        </div>
        <div className="header-right">
          <button 
            className="clear-btn" 
            onClick={clearChatHistory}
            title="Clear chat history"
          >
            Clear
          </button>
          <button className="close-btn" onClick={onClose}>
            <X size={20} />
          </button>
        </div>
      </div>

      {/* Messages Container */}
      <div className="messages-container">
        {messages.map((msg) => (
          <div key={msg.id} className={`message-bubble ${msg.sender} ${msg.type || ''}`}>
            <div className="message-icon">{msg.icon}</div>
            <div className="message-content">
              <div className="message-text">
                {msg.text.split('\n').map((line, i) => (
                  <React.Fragment key={i}>
                    {line}
                    {i < msg.text.split('\n').length - 1 && <br />}
                  </React.Fragment>
                ))}
              </div>
              <div className="message-meta">
                <div className="message-time">
                  <Clock size={10} />
                  {msg.timestamp}
                </div>
                {msg.sender === 'bot' && msg.type !== 'welcome' && (
                  <div className="message-type">
                    • AI Response
                  </div>
                )}
              </div>
            </div>
          </div>
        ))}
        
        {isTyping && (
          <div className="message-bubble bot typing">
            <div className="message-icon">🤖</div>
            <div className="message-content">
              <div className="typing-indicator">
                <span></span>
                <span></span>
                <span></span>
              </div>
            </div>
          </div>
        )}
        
        <div ref={messagesEndRef} />
      </div>

      {/* Quick Suggestions */}
      {suggestions.length > 0 && (
        <div className="quick-suggestions">
          <div className="suggestions-header">
            <Sparkles size={16} />
            <span>Quick Questions</span>
          </div>
          <div className="suggestions-grid">
            {suggestions.map((suggestion, index) => (
              <button
                key={index}
                className="suggestion-btn"
                onClick={() => handleQuickQuestion(suggestion.text)}
                disabled={isLoading || connectionStatus !== 'connected'}
              >
                <span className="suggestion-icon">{suggestion.icon}</span>
                <span className="suggestion-text">{suggestion.text}</span>
                <ChevronRight size={14} />
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Input Area */}
      <div className="input-container">
        <div className="input-wrapper">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyPress={handleKeyPress}
            placeholder="Ask about your fees, attendance, grades, timetable..."
            className="chat-input"
            disabled={isLoading || connectionStatus !== 'connected'}
          />
          <button
            onClick={handleSend}
            disabled={!input.trim() || isLoading || connectionStatus !== 'connected'}
            className="send-btn"
          >
            {isLoading ? (
              <Loader2 size={18} className="spin" />
            ) : (
              <Send size={18} />
            )}
          </button>
        </div>
        <div className="input-hint">
          {connectionStatus === 'connected' 
            ? 'Press Enter to send • Shift+Enter for new line'
            : 'Chatbot service is currently unavailable'
          }
        </div>
      </div>
    </div>
  );
};

export default ERPChatBot;
